var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이런 자리에서는 원래대로 존대해도 괜찮겠죠, 관리자님.","JPN":"このような席では元どおり敬語でいいですね、管理者殿。","ENG":"Since it's just you and me here, I suppose I can speak to you with due respect as I've done in the past, Administrator?","TWN":"在這裡可以照舊使用敬語吧，管理者大人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"사실...... 부족한 제게 이런 기회를 주실 줄은 몰랐습니다.","JPN":"実は……未熟な私に、こういった機会を与えてくださるとは思ってませんでした。","ENG":"To be honest... I never imagined you'd give me such an undeserved opportunity.","TWN":"其實……我沒想到您會給我這樣的機會。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그 제안, 놓치고 싶지......","JPN":"そのご提案、逃したくありま……","ENG":"I wouldn't miss your offer for the world—","TWN":"您的提議，我當然不想錯過……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"거리감이 느껴지니 평소처럼 편하게 대해 달라......는 말씀이십니까.","JPN":"距離感を感じるから、\\n普段どおり気軽に接してほしい、ですか……","ENG":"Oh, you'd like me to treat you like I've been doing? All this formality makes you uncomfortable?","TWN":"您說您覺得有點距離感，希望我像平時一樣……是嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"몰랐는데 소문과 다르게 조금 짓궂은 면도 있으십니다.","JPN":"知らなかったのですが、噂と違って少し意地悪なところもあるんですね。","ENG":"I never realized you had such a naughty humorous side to you.","TWN":"沒想到您跟傳聞中的不一樣，也有壞心眼的一面呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"크흠, 흠. 평소처럼 하라고 해도 다르지는 않을 것 같군.","JPN":"お、おほん。\\n普段どおりと言われても、そう変わらないかもしれない。","ENG":"Ahem... Well, I don't think there'll be much difference even if I do treat you like always.","TWN":"咳咳，咳。就算你叫我像平時那樣，但好像也不會有什麼不同。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"예전부터 다른 사람과 말을 하다 보면 분위기가 어느새 어색해졌거든.","JPN":"昔から他人と話していると、いつの間にか気まずい雰囲気になってしまうんだ。","ENG":"Things always get awkward when I try to talk to people.","TWN":"從以前開始，我跟別人聊著聊著，氣氛就會在不知不覺間變得很尷尬。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"내게 먼저 말을 걸어 줬던 사람도 수연이뿐이었으니까.","JPN":"私に先に声をかけてくれたのも、キズナだけだったから。","ENG":"Sooyeon was the only person who ever talked to me first.","TWN":"所以會先跟我說話的人只有秀妍。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......또 혼자 생각에 빠져 버렸군. 혼자 지내는 동안 버릇이 들었어.","JPN":"……また一人で考え込んでしまったな。一人で過ごしているうちに癖になったんだ。","ENG":"Here I go getting lost in my thoughts again. I've developed this habit while spending to much time alone.","TWN":"……我又一個人陷入沉思了呢。一個人生活時養成了這個習慣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"하지만 너를 대하는 자세가 어떻든 간에, 내 대답은 변함없을 거다.","JPN":"しかし、君に対する態度がどうであれ、私の返事は変わらない。","ENG":"But regardless of how I treat you, my answer's the same.","TWN":"不過，不管對待你的態度是如何，我的答案都不會改變。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"내가 따라야 할 사람으로서.","JPN":"私が従うべき人間として。","ENG":"You are someone I must follow.","TWN":"作為我跟隨的人……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그리고, 그 길었던 전쟁에 종지부를 찍게 도와 준 전우로서.","JPN":"そして、あの長かった戦争に終止符を打てるように助けてくれた戦友として。","ENG":"And you have helped me put an end to that never-ending war.","TWN":"以及在那場漫長的戰爭中，幫我們畫上休止符的戰友，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"삶을 마치는 그날까지, 너는 내게 없어서는 안 될 존재니까.","JPN":"命が果てるその日まで、君は私にとってなくてはならない存在だから。","ENG":"Until the day I draw my last breath, I need you.","TWN":"直到生命結束的那一天，你都是我不可或缺的存在。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"명령해 다오, 전우여. 그 끝에 무엇이 기다리고 있든 너와 함께하겠다.","JPN":"命じてくれ、戦友よ。その果てに何が待っていようと、君について行く。","ENG":"So give me your orders, comrade. I will always be your side, no matter what awaits us.","TWN":"下命令吧，戰友。不管在那個盡頭等待的是什麼，我都會跟你在一起。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};